has 'db';

sub authorize($self) {

    try {
        my $tx = $self->db->begin;
        my @functions = (
            "kanban_list",
            "kanban_planboard",
            "kanban_cards",
            "kanban_assignees",
            "kanban_comments",
            "kanban_priority",
            "kanban_attachments",
            "kanban_tasks",
